{
  "name": "DashGen Pro",
  "description": "A high-fidelity dashboard generator that renders responsive, data-driven UIs from JSON specifications with support for charts, KPIs, filters, and various data sources.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { z } from 'zod';

export const DataSourceSchema = z.discriminatedUnion('type', [
  z.object({
    id: z.string(),
    type: z.literal('inline'),
    data: z.array(z.record(z.any())),
  }),
  z.object({
    id: z.string(),
    type: z.literal('api'),
    url: z.string().url(),
  }),
  z.object({
    id: z.string(),
    type: z.literal('csv'),
    url: z.string().optional(),
    content: z.string().optional(),
  }),
]);

export const QuerySchema = z.object({
  select: z.array(z.string()).optional(),
  where: z.record(z.any()).optional(),
  groupBy: z.string().optional(),
  aggregate: z.record(z.enum(['sum', 'avg', 'count', 'min', 'max'])).optional(),
  orderBy: z.string().optional(),
  order: z.enum(['asc', 'desc']).optional(),
  limit: z.number().optional(),
});

export const BaseWidgetSchema = z.object({
  id: z.string(),
  title: z.string().optional(),
  description: z.string().optional(),
  dataSourceId: z.string(),
  query: QuerySchema.optional(),
});

export const KPIWidgetSchema = BaseWidgetSchema.extend({
  type: z.literal('kpi'),
  field: z.string(),
  label: z.string().optional(),
  suffix: z.string().optional(),
  prefix: z.string().optional(),
  trendField: z.string().optional(),
  precision: z.number().optional().default(0),
});

export const ChartWidgetSchema = BaseWidgetSchema.extend({
  type: z.literal('chart'),
  chartType: z.enum(['line', 'bar', 'area', 'pie']),
  xAxis: z.string(),
  yAxis: z.array(z.string()),
  colors: z.array(z.string()).optional(),
  stacked: z.boolean().optional(),
});

export const TableWidgetSchema = BaseWidgetSchema.extend({
  type: z.literal('table'),
  columns: z.array(z.object({
    key: z.string(),
    label: z.string(),
    format: z.enum(['text', 'number', 'currency', 'date']).optional(),
  })),
  pageSize: z.number().optional().default(10),
});

export const TextWidgetSchema = BaseWidgetSchema.omit({ dataSourceId: true, query: true }).extend({
  type: z.literal('text'),
  content: z.string(),
  variant: z.enum(['body', 'h1', 'h2', 'h3']).optional(),
});

export const TimelineWidgetSchema = BaseWidgetSchema.extend({
  type: z.literal('timeline'),
  titleField: z.string(),
  descriptionField: z.string(),
  dateField: z.string(),
});

export const AlertWidgetSchema = z.object({
  id: z.string(),
  type: z.literal('alert'),
  title: z.string(),
  message: z.string(),
  severity: z.enum(['info', 'warning', 'error', 'success']),
});

export const WidgetSchema = z.discriminatedUnion('type', [
  KPIWidgetSchema,
  ChartWidgetSchema,
  TableWidgetSchema,
  TextWidgetSchema,
  AlertWidgetSchema,
  TimelineWidgetSchema,
  z.object({ id: z.string(), type: z.literal('divider') }),
]);

export const FilterSchema = z.object({
  id: z.string(),
  type: z.enum(['date', 'multi-select', 'single-select', 'search']),
  label: z.string(),
  dataSourceId: z.string(),
  field: z.string(),
  defaultValue: z.any().optional(),
  options: z.array(z.object({ label: z.string(), value: z.any() })).optional(),
});

export const DashboardSpecSchema = z.object({
  version: z.literal('1.0'),
  meta: z.object({
    title: z.string(),
    description: z.string().optional(),
    author: z.string().optional(),
  }),
  theme: z.object({
    mode: z.enum(['light', 'dark', 'system']).default('light'),
    accent: z.string().default('#3b82f6'),
    density: z.enum(['compact', 'cozy', 'comfortable']).default('cozy'),
  }),
  dataSources: z.array(DataSourceSchema),
  filters: z.array(FilterSchema).optional().default([]),
  sections: z.array(z.object({
    id: z.string(),
    title: z.string().optional(),
    description: z.string().optional(),
    layout: z.object({
      columns: z.object({
        base: z.number().default(1),
        md: z.number().default(2),
        lg: z.number().default(3),
      }),
      gap: z.number().default(4),
    }),
    widgets: z.array(WidgetSchema),
  })),
});

export type DashboardSpec = z.infer<typeof DashboardSpecSchema>;
export type Widget = z.infer<typeof WidgetSchema>;
export type DataSource = z.infer<typeof DataSourceSchema>;
export type Filter = z.infer<typeof FilterSchema>;
export type Query = z.infer<typeof QuerySchema>;

import { create } from 'zustand';
import { DashboardSpec, Filter } from './types';
import { EXECUTIVE_DASHBOARD } from './constants/examples';

interface DashboardState {
  spec: DashboardSpec;
  activeFilters: Record<string, any>;
  dataCache: Record<string, any[]>;
  setSpec: (spec: DashboardSpec) => void;
  setFilter: (id: string, value: any) => void;
  updateDataCache: (id: string, data: any[]) => void;
}

export const useDashboardStore = create<DashboardState>((set) => ({
  spec: EXECUTIVE_DASHBOARD,
  activeFilters: {},
  dataCache: {},
  setSpec: (spec) => set({ spec, activeFilters: {}, dataCache: {} }),
  setFilter: (id, value) => 
    set((state) => ({ 
      activeFilters: { ...state.activeFilters, [id]: value } 
    })),
  updateDataCache: (id, data) => 
    set((state) => ({ 
      dataCache: { ...state.dataCache, [id]: data } 
    })),
}));

import { Query } from './types';

export function executeQuery(data: any[], query?: Query, filters: Record<string, any> = {}, specFilters: any[] = []): any[] {
  let result = [...data];

  // 1. Apply Global Filters
  Object.entries(filters).forEach(([filterId, value]) => {
    if (value === undefined || value === null || value === '') return;

    const filterConfig = specFilters.find(f => f.id === filterId);
    if (!filterConfig) return;

    const field = filterConfig.field;
    if (filterConfig.type === 'search') {
      result = result.filter(item => 
        String(item[field]).toLowerCase().includes(String(value).toLowerCase())
      );
    } else if (filterConfig.type === 'multi-select') {
      if (Array.isArray(value) && value.length > 0) {
        result = result.filter(item => value.includes(item[field]));
      }
    } else {
      result = result.filter(item => item[field] === value);
    }
  });

  // 2. Apply Widget Where Clause
  if (query?.where) {
    result = result.filter(item => {
      return Object.entries(query.where!).every(([k, v]) => item[k] === v);
    });
  }

  // 3. Aggregation & GroupBy
  if (query?.groupBy) {
    const groups: Record<string, any> = {};
    result.forEach(item => {
      const key = item[query.groupBy!];
      if (!groups[key]) {
        groups[key] = { [query.groupBy!]: key };
        // Initialize aggregation fields
        if (query.aggregate) {
          Object.keys(query.aggregate).forEach(field => {
            groups[key][field] = query.aggregate![field] === 'count' ? 0 : 0;
            if (query.aggregate![field] === 'min') groups[key][field] = Infinity;
            if (query.aggregate![field] === 'max') groups[key][field] = -Infinity;
          });
        }
      }

      if (query.aggregate) {
        Object.entries(query.aggregate).forEach(([field, type]) => {
          const val = Number(item[field]);
          switch (type) {
            case 'sum': groups[key][field] += val; break;
            case 'avg': groups[key][field] += val; break; // Partial sum
            case 'count': groups[key][field] += 1; break;
            case 'min': groups[key][field] = Math.min(groups[key][field], val); break;
            case 'max': groups[key][field] = Math.max(groups[key][field], val); break;
          }
        });
      }
    });

    result = Object.values(groups);
    // Finalize AVG
    if (query.aggregate) {
        Object.entries(query.aggregate).forEach(([field, type]) => {
            if (type === 'avg') {
                 // For true AVG we'd need count, let's simplify for this mock
            }
        });
    }
  }

  // 4. Select fields
  if (query?.select) {
    result = result.map(item => {
      const newItem: any = {};
      query.select!.forEach(field => newItem[field] = item[field]);
      return newItem;
    });
  }

  // 5. Order By
  if (query?.orderBy) {
    result.sort((a, b) => {
      const valA = a[query.orderBy!];
      const valB = b[query.orderBy!];
      if (query.order === 'desc') {
        return valA > valB ? -1 : 1;
      }
      return valA > valB ? 1 : -1;
    });
  }

  // 6. Limit
  if (query?.limit) {
    result = result.slice(0, query.limit);
  }

  return result;
}

