export const DashboardRenderer: React.FC = () => {
  const { spec, activeFilters } = useDashboardStore();

  const getWidgetData = (widget: any) => {
    const ds = spec.dataSources.find(d => d.id === widget.dataSourceId);
    if (!ds || ds.type !== 'inline') return [];
    return executeQuery(ds.data, widget.query, activeFilters, spec.filters);
  };

  const renderWidget = (widget: Widget) => {
    const data = (widget as any).dataSourceId ? getWidgetData(widget) : [];

    switch (widget.type) {
      case 'kpi':
        return <KPIWidget key={widget.id} {...widget} data={data} />;
      case 'chart':
        return <ChartWidget key={widget.id} {...widget} data={data} accent={spec.theme.accent} />;
      case 'table':
        return <TableWidget key={widget.id} {...widget} data={data} />;
      case 'alert':
        const severityStyles = {
          info: 'bg-blue-50 text-blue-800 border-blue-200',
          warning: 'bg-amber-50 text-amber-800 border-amber-200',
          error: 'bg-red-50 text-red-800 border-red-200',
          success: 'bg-emerald-50 text-emerald-800 border-emerald-200',
