        return (
          <div key={widget.id} className={`p-4 rounded-lg border ${severityStyles[widget.severity]} mb-4`}>
            <div className="flex items-center gap-2 font-bold mb-1">
                <span>{widget.title}</span>
            </div>
            <p className="text-sm">{widget.message}</p>
          </div>
        );
      case 'divider':
        return <hr key={widget.id} className="my-6 border-slate-200 col-span-full" />;
      case 'text':
        const variantStyles = {
          h1: 'text-3xl font-bold text-slate-900',
          h2: 'text-2xl font-semibold text-slate-800',
          h3: 'text-xl font-medium text-slate-700',
          body: 'text-slate-600 leading-relaxed',
        };
        return <div key={widget.id} className={variantStyles[widget.variant || 'body']}>{widget.content}</div>;
      case 'timeline':
        return (
          <div key={widget.id} className="space-y-4">
             {data.map((item, i) => (
               <div key={i} className="flex gap-4 border-l-2 border-slate-200 pl-6 relative">
                 <div className="absolute w-3 h-3 bg-white border-2 border-blue-500 rounded-full -left-[7.5px] top-1"></div>
                 <div>
                    <span className="text-xs text-slate-400 block mb-1">{item[widget.dateField]}</span>
                    <h4 className="font-semibold text-sm">{item[widget.titleField]}</h4>
                    <p className="text-xs text-slate-500">{String(item[widget.descriptionField])}</p>
                 </div>
               </div>
             ))}
          </div>
        );
      default:
        return <div key={widget.id} className="p-4 bg-slate-100 rounded text-xs text-slate-400">Widget Type "{widget.type}" Not Supported</div>;
    }
  };

  return (
    <div className="dashboard-container space-y-12 pb-12">
      {spec.sections.map((section) => (
        <section key={section.id}>
          {(section.title || section.description) && (
            <div className="mb-6">
              {section.title && <h2 className="text-xl font-bold text-slate-900 tracking-tight">{section.title}</h2>}
              {section.description && <p className="text-sm text-slate-500 mt-1">{section.description}</p>}
            </div>
          )}
          <div 
            className="grid gap-6"
            style={{ 
              gridTemplateColumns: `repeat(auto-fit, minmax(300px, 1fr))` 
            }}
          >
            {section.widgets.map(widget => renderWidget(widget))}
          </div>
        </section>
      ))}
    </div>
  );
};

