import React, { useState } from 'react';
import { Card } from '../UI/Card';
import { TableWidgetSchema } from '../../types';
import { z } from 'zod';

type TableProps = z.infer<typeof TableWidgetSchema> & { data: any[] };

export const TableWidget: React.FC<TableProps> = ({ title, columns, data = [], pageSize = 10 }) => {
  const [page, setPage] = useState(0);
  const totalPages = Math.ceil(data.length / pageSize);
  const paginatedData = data.slice(page * pageSize, (page + 1) * pageSize);

  const formatValue = (val: any, format?: string) => {
    if (val === null || val === undefined) return '-';
    switch (format) {
      case 'currency': return `$${Number(val).toLocaleString()}`;
      case 'number': return Number(val).toLocaleString();
      case 'date': return new Date(val).toLocaleDateString();
      default: return String(val);
    }
  };

  const handleExport = () => {
    const headers = columns.map(c => c.label).join(',');
    const rows = data.map(row => columns.map(c => row[c.key]).join(',')).join('\n');
    const blob = new Blob([`${headers}\n${rows}`], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${title || 'export'}.csv`;
    a.click();
  };

  return (
    <Card 
      title={title} 
      footer={
        <div className="flex items-center justify-between no-print">
            <span className="text-xs text-slate-500">Showing {paginatedData.length} of {data.length} records</span>
            <div className="flex gap-2">
                <button 
                  onClick={() => setPage(p => Math.max(0, p - 1))}
                  disabled={page === 0}
                  className="px-2 py-1 text-xs border rounded disabled:opacity-50"
                >Prev</button>
                <button 
                  onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
                  disabled={page >= totalPages - 1}
                  className="px-2 py-1 text-xs border rounded disabled:opacity-50"
                >Next</button>
            </div>
        </div>
      }
    >
      <div className="mb-4 flex justify-end no-print">
        <button 
          onClick={handleExport}
          className="text-xs text-blue-600 font-medium hover:underline flex items-center gap-1"
        >
          Download CSV
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm border-collapse">
          <thead>
            <tr className="border-b border-slate-100">
              {columns.map(col => (
                <th key={col.key} className="py-2 px-3 font-semibold text-slate-600">{col.label}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {paginatedData.map((row, i) => (
              <tr key={i} className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors">
                {columns.map(col => (
                  <td key={col.key} className="py-2.5 px-3 text-slate-700">
                    {formatValue(row[col.key], col.format)}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </Card>
  );
};

import React from 'react';
import { Card } from '../UI/Card';
import { KPIWidgetSchema } from '../../types';
import { z } from 'zod';

type KPIProps = z.infer<typeof KPIWidgetSchema> & { data: any[] };

export const KPIWidget: React.FC<KPIProps> = ({ title, data = [], field, prefix, suffix, precision = 0 }) => {
  const value = data.length > 0 ? data[0][field] : 0;
  const formattedValue = typeof value === 'number' 
    ? value.toLocaleString(undefined, { minimumFractionDigits: precision, maximumFractionDigits: precision })
    : value;

  return (
    <Card className="hover:border-slate-300 transition-colors">
      <div className="flex flex-col">
        <span className="text-xs font-medium text-slate-500 uppercase tracking-wider">{title}</span>
        <div className="mt-2 flex items-baseline gap-1">
          {prefix && <span className="text-xl font-medium text-slate-400">{prefix}</span>}
          <span className="text-3xl font-bold text-slate-900 tracking-tight">{formattedValue}</span>
          {suffix && <span className="text-sm font-medium text-slate-400">{suffix}</span>}
        </div>
      </div>
    </Card>
  );
};

import React from 'react';
import { Card } from '../UI/Card';
import { 
  LineChart, Line, BarChart, Bar, AreaChart, Area, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from 'recharts';
import { ChartWidgetSchema } from '../../types';
import { z } from 'zod';

type ChartProps = z.infer<typeof ChartWidgetSchema> & { data: any[], accent?: string };

const DEFAULT_COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#6366f1'];

export const ChartWidget: React.FC<ChartProps> = ({ title, chartType, data = [], xAxis, yAxis, colors, accent }) => {
  const chartColors = colors || [accent || '#3b82f6', ...DEFAULT_COLORS];

  const renderChart = () => {
    switch (chartType) {
      case 'line':
        return (
          <LineChart data={data}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
            <XAxis dataKey={xAxis} fontSize={12} tickLine={false} axisLine={false} />
            <YAxis fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => val >= 1000 ? `${val/1000}k` : val} />
            <Tooltip contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} />
            <Legend verticalAlign="top" height={36} iconType="circle" />
            {yAxis.map((key, i) => (
              <Line key={key} type="monotone" dataKey={key} stroke={chartColors[i % chartColors.length]} strokeWidth={2} dot={{ r: 4 }} activeDot={{ r: 6 }} />
            ))}
          </LineChart>
        );
      case 'bar':
        return (
          <BarChart data={data}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
            <XAxis dataKey={xAxis} fontSize={12} tickLine={false} axisLine={false} />
            <YAxis fontSize={12} tickLine={false} axisLine={false} />
            <Tooltip cursor={{ fill: '#f8fafc' }} contentStyle={{ borderRadius: '8px', border: 'none' }} />
            <Legend verticalAlign="top" height={36} />
            {yAxis.map((key, i) => (
              <Bar key={key} dataKey={key} fill={chartColors[i % chartColors.length]} radius={[4, 4, 0, 0]} />
            ))}
          </BarChart>
        );
      case 'area':
        return (
          <AreaChart data={data}>
             <defs>
              {yAxis.map((key, i) => (
                <linearGradient key={`grad-${key}`} id={`grad-${key}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={chartColors[i % chartColors.length]} stopOpacity={0.3}/>
                  <stop offset="95%" stopColor={chartColors[i % chartColors.length]} stopOpacity={0}/>
                </linearGradient>
              ))}
            </defs>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
            <XAxis dataKey={xAxis} fontSize={12} tickLine={false} axisLine={false} />
            <YAxis fontSize={12} tickLine={false} axisLine={false} />
            <Tooltip />
            {yAxis.map((key, i) => (
              <Area key={key} type="monotone" dataKey={key} stroke={chartColors[i % chartColors.length]} fillOpacity={1} fill={`url(#grad-${key})`} strokeWidth={2} />
            ))}
          </AreaChart>
        );
      case 'pie':
        return (
            <PieChart>
                <Pie 
                    data={data} 
                    dataKey={yAxis[0]} 
                    nameKey={xAxis} 
                    cx="50%" 
                    cy="50%" 
                    innerRadius={60} 
                    outerRadius={80} 
                    paddingAngle={5}
                >
                    {data.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={chartColors[index % chartColors.length]} />
                    ))}
                </Pie>
                <Tooltip />
                <Legend layout="vertical" align="right" verticalAlign="middle" />
            </PieChart>
        );
    }
  };

  return (
    <Card title={title}>
      <div className="h-[280px] w-full">
        <ResponsiveContainer width="100%" height="100%">
          {renderChart()}
        </ResponsiveContainer>
      </div>
    </Card>
  );
};

import { DashboardSpec, DashboardSpecSchema } from '../types';

/**
 * Encodes a DashboardSpec into a base64 string for URL sharing.
 */
export function encodeSpec(spec: DashboardSpec): string {
  const json = JSON.stringify(spec);
  // Using encodeURIComponent + btoa for UTF-8 support
  return btoa(encodeURIComponent(json).replace(/%([0-9A-F]{2})/g, (_, p1) => 
    String.fromCharCode(parseInt(p1, 16))
  ));
}

/**
 * Decodes a base64 string back into a validated DashboardSpec.
 */
export function decodeSpec(encoded: string): DashboardSpec | null {
  try {
    const json = decodeURIComponent(Array.prototype.map.call(atob(encoded), (c) => 
      '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2)
    ).join(''));
    const parsed = JSON.parse(json);
    return DashboardSpecSchema.parse(parsed);
  } catch (e) {
    console.error('Failed to decode spec from URL', e);
    return null;
  }
}

/**
 * Generates a shareable URL for the current specification.
 */
export function getShareableUrl(spec: DashboardSpec, readOnly: boolean = false): string {
  const encoded = encodeSpec(spec);
  const url = new URL(window.location.href);
  url.searchParams.set('spec', encoded);
  if (readOnly) {
    url.searchParams.set('viewOnly', 'true');
  }
  return url.toString();
}

