import { Query, DataSource } from './types';

/**
 * Executes a query against a dataset locally.
 */
export function executeQuery(data: any[], query?: Query, filters: Record<string, any> = {}, specFilters: any[] = []): any[] {
  if (!data) return [];
  let result = [...data];

  // 1. Apply Global Filters
  Object.entries(filters).forEach(([filterId, value]) => {
    if (value === undefined || value === null || value === '' || (Array.isArray(value) && value.length === 0)) return;

    const filterConfig = specFilters.find(f => f.id === filterId);
    if (!filterConfig) return;

    const field = filterConfig.field;
    if (filterConfig.type === 'search') {
      result = result.filter(item => 
        String(item[field]).toLowerCase().includes(String(value).toLowerCase())
      );
    } else if (filterConfig.type === 'date') {
      // Expecting value to be { start?: string, end?: string }
      if (typeof value === 'object') {
        if (value.start) {
          result = result.filter(item => new Date(item[field]) >= new Date(value.start));
        }
        if (value.end) {
          result = result.filter(item => new Date(item[field]) <= new Date(value.end));
        }
      } else {
        // Fallback for exact match if single string passed
        result = result.filter(item => item[field] === value);
      }
    } else if (filterConfig.type === 'multi-select') {
      if (Array.isArray(value)) {
        result = result.filter(item => value.includes(item[field]));
      }
    } else {
      result = result.filter(item => item[field] === value);
    }
  });

  // 2. Apply Widget Where Clause
  if (query?.where) {
    result = result.filter(item => {
      return Object.entries(query.where!).every(([k, v]) => item[k] === v);
    });
  }

  // 3. Aggregation & GroupBy
  if (query?.groupBy) {
    const groups: Record<string, any> = {};
    result.forEach(item => {
      const key = String(item[query.groupBy!]);
      if (!groups[key]) {
        groups[key] = { [query.groupBy!]: key };
        if (query.aggregate) {
          Object.keys(query.aggregate).forEach(field => {
            groups[key][field] = 0;
            if (query.aggregate![field] === 'min') groups[key][field] = Infinity;
            if (query.aggregate![field] === 'max') groups[key][field] = -Infinity;
          });
        }
      }

      if (query.aggregate) {
        Object.entries(query.aggregate).forEach(([field, type]) => {
          const val = Number(item[field]) || 0;
          switch (type) {
            case 'sum': groups[key][field] += val; break;
            case 'avg': groups[key][field] += val; break; 
            case 'count': groups[key][field] += 1; break;
            case 'min': groups[key][field] = Math.min(groups[key][field], val); break;
            case 'max': groups[key][field] = Math.max(groups[key][field], val); break;
          }
        });
      }
    });
    result = Object.values(groups);
  }

  // 4. Order By
  if (query?.orderBy) {
    result.sort((a, b) => {
      const valA = a[query.orderBy!];
      const valB = b[query.orderBy!];
      return query.order === 'desc' ? (valA > valB ? -1 : 1) : (valA > valB ? 1 : -1);
    });
  }

  // 5. Limit
  if (query?.limit) {
    result = result.slice(0, query.limit);
  }

  return result;
}

/**
 * Resolves a DataSource into an array of records.
 */
export async function resolveDataSource(ds: DataSource): Promise<any[]> {
  if (ds.type === 'inline') return ds.data;

  if (ds.type === 'csv') {
    if (ds.content) return parseCSV(ds.content);
    if (ds.url) {
      try {
        const resp = await fetch(ds.url);
        if (!resp.ok) throw new Error(`CSV fetch failed: ${resp.statusText}`);
        const text = await resp.text();
        return parseCSV(text);
      } catch (e) {
        console.error(`Failed to load CSV source ${ds.id}`, e);
        return [];
      }
    }
  }

  if (ds.type === 'api') {
    try {
      const resp = await fetch(ds.url);
      if (!resp.ok) throw new Error(`API fetch failed: ${resp.statusText}`);
      return await resp.json();
    } catch (e) {
      console.error(`Failed to load API source ${ds.id}`, e);
      return [];
    }
  }

  return [];
}

function parseCSV(text: string): any[] {
  const lines = text.trim().split('\n');
  if (lines.length < 2) return [];
  const headers = lines[0].split(',').map(h => h.trim());
  return lines.slice(1).map(line => {
    const values = line.split(',');
    return headers.reduce((obj: any, header, i) => {
      const val = values[i]?.trim();
      obj[header] = isNaN(Number(val)) ? val : Number(val);
      return obj;
    }, {});
  });
}

import React from 'react';
import { Card } from '../UI/Card';
import { TimelineWidgetSchema } from '../../types';
import { z } from 'zod';

type TimelineProps = z.infer<typeof TimelineWidgetSchema> & { data: any[] };

export const TimelineWidget: React.FC<TimelineProps> = ({ title, data = [], dateField, titleField, descriptionField }) => {
  // Ensure data is sorted chronologically
  const sortedData = [...data].sort((a, b) => {
    return new Date(b[dateField]).getTime() - new Date(a[dateField]).getTime();
  });

  return (
    <Card title={title}>
      <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2">
        {sortedData.length === 0 && <p className="text-sm text-slate-400 italic">No events found.</p>}
        {sortedData.map((item, i) => (
          <div key={i} className="flex gap-4 border-l-2 border-slate-200 pl-6 relative pb-1">
            <div className="absolute w-3 h-3 bg-white border-2 border-blue-500 rounded-full -left-[7px] top-1.5 transition-colors hover:bg-blue-50"></div>
            <div className="flex-1">
               <span className="text-[10px] text-slate-400 block mb-0.5 uppercase font-bold tracking-wider">
                 {new Date(item[dateField]).toLocaleDateString()}
               </span>
               <h4 className="font-bold text-slate-900 text-sm">{item[titleField]}</h4>
               {descriptionField && (
                 <p className="text-xs text-slate-500 mt-1 leading-relaxed">
                   {String(item[descriptionField])}
                 </p>
               )}
            </div>
          </div>
        ))}
      </div>
    </Card>
  );
};

import React, { useState, useRef } from 'react';
import { Card } from '../UI/Card';
import { TableWidgetSchema } from '../../types';
import { z } from 'zod';

type TableProps = z.infer<typeof TableWidgetSchema> & { data: any[] };

export const TableWidget: React.FC<TableProps> = ({ title, columns, data = [], pageSize = 10 }) => {
  const [page, setPage] = useState(0);
  const tableRef = useRef<HTMLDivElement>(null);
  const totalPages = Math.ceil(data.length / pageSize);
  const paginatedData = data.slice(page * pageSize, (page + 1) * pageSize);

  const formatValue = (val: any, format?: string) => {
    if (val === null || val === undefined) return '-';
    switch (format) {
      case 'currency': return `$${Number(val).toLocaleString()}`;
      case 'number': return Number(val).toLocaleString();
      case 'date': return new Date(val).toLocaleDateString();
      default: return String(val);
    }
  };

  const handleExport = () => {
    const headers = columns.map(c => c.label).join(',');
    const rows = data.map(row => columns.map(c => row[c.key]).join(',')).join('\n');
    const blob = new Blob([`${headers}\n${rows}`], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${title || 'export'}.csv`;
    a.click();
  };

  const handlePrint = () => {
    if (tableRef.current) {
      // Add a class to the card to target it in CSS
      tableRef.current.classList.add('print-target');
      document.body.classList.add('printing-mode');

      window.print();

      // Cleanup
      document.body.classList.remove('printing-mode');
      tableRef.current.classList.remove('print-target');
    }
  };

  return (
    <div ref={tableRef} className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full">
      {(title) && (
        <div className="px-5 py-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
          <h3 className="text-sm font-semibold text-slate-900">{title}</h3>
          <div className="flex gap-2 no-print">
            <button 
              onClick={handlePrint}
              className="text-xs text-slate-600 hover:text-blue-600 font-medium flex items-center gap-1"
            >
              Print PDF
            </button>
            <button 
              onClick={handleExport}
              className="text-xs text-blue-600 font-medium hover:underline flex items-center gap-1"
            >
              CSV
            </button>
          </div>
        </div>
      )}
      <div className="p-0 flex-1">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead>
              <tr className="border-b border-slate-100 bg-slate-50/30">
                {columns.map(col => (
                  <th key={col.key} className="py-3 px-4 font-semibold text-slate-600">{col.label}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {paginatedData.map((row, i) => (
                <tr key={i} className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors">
                  {columns.map(col => (
                    <td key={col.key} className="py-2.5 px-4 text-slate-700">
                      {formatValue(row[col.key], col.format)}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <div className="px-5 py-3 border-t border-slate-100 bg-slate-50/50 flex items-center justify-between no-print">
          <span className="text-xs text-slate-500">Showing {paginatedData.length} of {data.length} records</span>
          <div className="flex gap-2">
              <button 
                onClick={() => setPage(p => Math.max(0, p - 1))}
                disabled={page === 0}
                className="px-2 py-1 text-xs border rounded disabled:opacity-50 hover:bg-white"
              >Prev</button>
              <button 
                onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
                disabled={page >= totalPages - 1}
                className="px-2 py-1 text-xs border rounded disabled:opacity-50 hover:bg-white"
              >Next</button>
          </div>
      </div>
    </div>
  );
};

import React from 'react';
import { useDashboardStore } from '../store';
import { executeQuery } from '../dataEngine';
import { KPIWidget } from './Widgets/KPIWidget';
import { ChartWidget } from './Widgets/ChartWidget';
import { TableWidget } from './Widgets/TableWidget';
import { TimelineWidget } from './Widgets/TimelineWidget';
import { Widget } from '../types';

export const DashboardRenderer: React.FC = () => {
  const { spec, activeFilters, dataCache, isLoading } = useDashboardStore();

  const getWidgetData = (widget: any) => {
    const data = dataCache[widget.dataSourceId] || [];
    return executeQuery(data, widget.query, activeFilters, spec.filters);
  };

  const renderWidget = (widget: Widget) => {
    if (isLoading) return <div key={widget.id} className="h-40 bg-slate-100 animate-pulse rounded-xl" />;

    const data = (widget as any).dataSourceId ? getWidgetData(widget) : [];

    switch (widget.type) {
      case 'kpi': return <KPIWidget key={widget.id} {...widget} data={data} />;
      case 'chart': return <ChartWidget key={widget.id} {...widget} data={data} accent={spec.theme.accent} />;
      case 'table': return <TableWidget key={widget.id} {...widget} data={data} />;
      case 'timeline': return <TimelineWidget key={widget.id} {...widget} data={data} />;
      case 'alert':
        const severityStyles = {
          info: 'bg-blue-50 text-blue-800 border-blue-200',
          warning: 'bg-amber-50 text-amber-800 border-amber-200',
          error: 'bg-red-50 text-red-800 border-red-200',
          success: 'bg-emerald-50 text-emerald-800 border-emerald-200',
        };
        return (
          <div key={widget.id} className={`p-4 rounded-lg border ${severityStyles[widget.severity]} mb-4 col-span-full`}>
            <div className="font-bold mb-1">{widget.title}</div>
            <p className="text-sm">{widget.message}</p>
          </div>
        );
      case 'divider': return <hr key={widget.id} className="my-6 border-slate-200 col-span-full" />;
      case 'text':
        const variantStyles = {
          h1: 'text-3xl font-bold text-slate-900',
          h2: 'text-2xl font-semibold text-slate-800',
          h3: 'text-xl font-medium text-slate-700',
          body: 'text-slate-600 leading-relaxed',
        };
        return <div key={widget.id} className={`${variantStyles[widget.variant || 'body']} col-span-full`}>{widget.content}</div>;
      default: return <div key={widget.id}>Unsupported Widget</div>;
    }
  };

  return (
    <div className="dashboard-container space-y-16 pb-20">
      {spec.sections.map((section) => (
        <section key={section.id}>
          {(section.title || section.description) && (
            <div className="mb-8 border-l-4 border-slate-200 pl-4">
              {section.title && <h2 className="text-2xl font-bold text-slate-900">{section.title}</h2>}
              {section.description && <p className="text-slate-500 mt-1">{section.description}</p>}
            </div>
          )}
          <div 
            className="grid gap-6"
            style={{ 
                gridTemplateColumns: `repeat(${section.layout.columns.lg}, 1fr)`,
                gap: `${section.layout.gap * 4}px`
            }}
          >
            {section.widgets.map(widget => renderWidget(widget))}
          </div>
        </section>
      ))}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useDashboardStore } from './store';
import { DashboardRenderer } from './components/DashboardRenderer';
import { DashboardBuilder } from './components/DashboardBuilder';
import { TemplateGallery } from './components/TemplateGallery';
import { DocsView } from './components/DocsView';
import { EXECUTIVE_DASHBOARD } from './constants/examples';
import { getShareableUrl, decodeSpec } from './utils/sharing';

const App: React.FC = () => {
  const { spec, activeFilters, setFilter, setSpec, loadData, isReadOnly, setReadOnly } = useDashboardStore();
  const [view, setView] = useState<'preview' | 'builder' | 'docs'>('preview');
  const [showTemplates, setShowTemplates] = useState(false);
  const [shareStatus, setShareStatus] = useState<'idle' | 'copied'>('idle');
  const [systemTheme, setSystemTheme] = useState<'light' | 'dark'>('light');

  // Listen for system theme changes
  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    setSystemTheme(mediaQuery.matches ? 'dark' : 'light');
    const handler = (e: MediaQueryListEvent) => setSystemTheme(e.matches ? 'dark' : 'light');
    mediaQuery.addEventListener('change', handler);
    return () => mediaQuery.removeEventListener('change', handler);
  }, []);

  const effectiveTheme = spec.theme.mode === 'system' ? systemTheme : spec.theme.mode;

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const sharedSpecEncoded = urlParams.get('spec');
    const viewOnlyParam = urlParams.get('viewOnly');

    if (sharedSpecEncoded) {
      const decoded = decodeSpec(sharedSpecEncoded);
      if (decoded) {
        setSpec(decoded);
        setReadOnly(true);
        setView('preview');
      }
    } else {
      loadData();
    }

    if (viewOnlyParam === 'true') {
      setReadOnly(true);
    }
  }, []);

  const handlePrint = () => window.print();

  const handleShare = () => {
    const url = getShareableUrl(spec, true);
    navigator.clipboard.writeText(url);
    setShareStatus('copied');
    setTimeout(() => setShareStatus('idle'), 2000);
  };

  const handleThemeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSpec({ ...spec, theme: { ...spec.theme, mode: e.target.value as any } });
  };

  const handleCsvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (isReadOnly) return;
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      const csvSourceId = `csv_${Date.now()}`;

      const newSpec = { ...spec };
      // Check if CSV sources exist and append, or add new
      const newDataSource = { id: csvSourceId, type: 'csv', content };
      newSpec.dataSources.push(newDataSource as any);

      setSpec(newSpec);
      alert(`CSV loaded with ID: ${csvSourceId}`);
    };
    reader.readAsText(file);
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${effectiveTheme === 'dark' ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <header className={`no-print border-b sticky top-0 z-30 px-8 h-16 flex items-center justify-between shadow-sm transition-colors duration-300 ${effectiveTheme === 'dark' ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-200'}`}>
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => { if(!isReadOnly) { setReadOnly(false); setView('preview'); } }}>
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-500/20">
                <span className="text-white font-bold text-xl">D</span>
            </div>
            <h1 className={`text-lg font-black tracking-tight ${effectiveTheme === 'dark' ? 'text-white' : 'text-slate-900'}`}>DASH<span className="text-blue-600">PRO</span></h1>
          </div>

          {!isReadOnly && (
            <nav className={`flex items-center p-1 rounded-xl ${effectiveTheme === 'dark' ? 'bg-slate-800' : 'bg-slate-100'}`}>
              <button onClick={() => setView('preview')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${view === 'preview' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-400'}`}>PREVIEW</button>
              <button onClick={() => setView('builder')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${view === 'builder' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-400'}`}>EDITOR</button>
              <button onClick={() => setView('docs')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${view === 'docs' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-400'}`}>DOCS</button>
            </nav>
          )}

          {isReadOnly && (
            <div className="flex items-center gap-2 px-3 py-1 bg-blue-50 border border-blue-200 rounded-lg">
               <span className="text-[10px] font-black text-blue-700 uppercase tracking-widest">Read Only Mode</span>
               <button onClick={() => setReadOnly(false)} className="text-[10px] text-blue-400 hover:text-blue-600 font-bold ml-2">Unlock</button>
            </div>
          )}
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center mr-2 border-r border-slate-700 pr-4">
            <select 
              value={spec.theme.mode} 
              onChange={handleThemeChange}
              className={`text-xs font-bold rounded-lg border px-2 py-1.5 outline-none cursor-pointer transition-colors ${
                effectiveTheme === 'dark' 
                  ? 'bg-slate-800 border-slate-700 text-slate-300 hover:bg-slate-700' 
                  : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
              }`}
            >
              <option value="light">☀️ Light</option>
              <option value="dark">🌙 Dark</option>
              <option value="system">🖥️ System</option>
            </select>
          </div>

          <button 
            onClick={() => setShowTemplates(true)}
            className={`text-xs font-bold transition-colors px-4 border-r ${effectiveTheme === 'dark' ? 'text-slate-400 hover:text-blue-400 border-slate-700' : 'text-slate-600 hover:text-blue-600 border-slate-200'}`}
          >
            TEMPLATES
          </button>

          <button 
            onClick={handleShare}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold transition-all border ${
              shareStatus === 'copied' 
                ? 'bg-emerald-500/10 border-emerald-500 text-emerald-500' 
                : effectiveTheme === 'dark'
                  ? 'bg-slate-800 border-slate-700 text-slate-300 hover:border-slate-600'
                  : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
            }`}
          >
            {shareStatus === 'copied' ? 'LINK COPIED' : 'SHARE'}
          </button>

          {!isReadOnly && (
            <label className={`text-xs px-4 py-2 rounded-lg font-bold cursor-pointer transition-colors border ${
              effectiveTheme === 'dark' 
                ? 'bg-slate-800 hover:bg-slate-700 border-slate-700 text-slate-300' 
                : 'bg-slate-100 hover:bg-slate-200 border-slate-200'
            }`}>
              UPLOAD CSV
              <input type="file" accept=".csv" className="hidden" onChange={handleCsvUpload} />
            </label>
          )}

          <button onClick={handlePrint} className="bg-blue-600 text-white px-5 py-2.5 rounded-lg text-xs font-bold hover:bg-blue-500 transition-all shadow-md shadow-blue-500/20">
            PDF
          </button>
        </div>
      </header>

      {view === 'preview' && spec.filters?.length > 0 && (
        <div className={`no-print backdrop-blur-md border-b px-10 py-5 flex flex-wrap items-end gap-8 sticky top-16 z-20 transition-colors duration-300 ${
          effectiveTheme === 'dark' ? 'bg-slate-900/80 border-slate-800' : 'bg-white/80 border-slate-200'
        }`}>
          {spec.filters.map(filter => (
            <div key={filter.id} className="flex flex-col gap-2">
              <label className={`text-[10px] font-black uppercase tracking-widest ${effectiveTheme === 'dark' ? 'text-slate-500' : 'text-slate-400'}`}>{filter.label}</label>

              {filter.type === 'multi-select' && (
                <div className="flex gap-2">
                   {filter.options?.map(opt => (
                     <button
                        key={opt.value}
                        onClick={() => {
                          const current = activeFilters[filter.id] || [];
                          const next = current.includes(opt.value) ? current.filter((v: any) => v !== opt.value) : [...current, opt.value];
                          setFilter(filter.id, next);
                        }}
                        className={`px-3 py-1.5 text-[11px] font-bold rounded-lg border transition-all ${
                          (activeFilters[filter.id] || []).includes(opt.value)
                            ? 'bg-blue-600 border-blue-600 text-white shadow-md shadow-blue-500/30'
                            : effectiveTheme === 'dark' 
                                ? 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'
                                : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                        }`}
                     >
                       {opt.label}
                     </button>
                   ))}
                </div>
              )}

              {filter.type === 'date' && (
                <div className="flex gap-2 items-center">
                  <input 
                    type="date"
                    className={`text-xs px-2 py-1.5 border rounded-lg outline-none transition-all ${
                      effectiveTheme === 'dark' ? 'bg-slate-800 border-slate-700 text-white' : 'bg-white border-slate-200'
                    }`}
                    onChange={(e) => setFilter(filter.id, { ...activeFilters[filter.id], start: e.target.value })}
                  />
                  <span className="text-slate-400">-</span>
                  <input 
                    type="date"
                    className={`text-xs px-2 py-1.5 border rounded-lg outline-none transition-all ${
                      effectiveTheme === 'dark' ? 'bg-slate-800 border-slate-700 text-white' : 'bg-white border-slate-200'
                    }`}
                    onChange={(e) => setFilter(filter.id, { ...activeFilters[filter.id], end: e.target.value })}
                  />
                </div>
              )}

              {(filter.type === 'search' || !['multi-select', 'date'].includes(filter.type)) && (
                <div className="relative">
                  <input 
                    className={`text-xs px-4 py-2 border rounded-lg outline-none w-64 transition-all pl-8 ${
                      effectiveTheme === 'dark' 
                        ? 'bg-slate-800 border-slate-700 text-white focus:border-blue-500' 
                        : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                    }`}
                    placeholder={`Search ${filter.field}...`}
                    onChange={(e) => setFilter(filter.id, e.target.value)}
                  />
                  <span className="absolute left-2.5 top-2 text-slate-400 text-xs">🔍</span>
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      <main className={`flex-1 p-10 transition-colors duration-300 ${effectiveTheme === 'dark' ? 'bg-slate-950' : 'bg-slate-50'}`}>
        <div className="max-w-7xl mx-auto">
          {view === 'preview' && (
            <div className="animate-in fade-in duration-500">
               <div className="mb-12">
                  <h1 className={`text-4xl font-black tracking-tight ${effectiveTheme === 'dark' ? 'text-white' : 'text-slate-900'}`}>{spec.meta.title}</h1>
                  {spec.meta.description && <p className={`mt-2 text-lg font-medium leading-relaxed max-w-3xl ${effectiveTheme === 'dark' ? 'text-slate-400' : 'text-slate-500'}`}>{spec.meta.description}</p>}
               </div>
               <DashboardRenderer />
            </div>
          )}
          {view === 'builder' && (
            <div className="h-[calc(100vh-180px)] animate-in slide-in-from-bottom-4 duration-300">
               <DashboardBuilder />
            </div>
          )}
          {view === 'docs' && <DocsView />}
        </div>
      </main>

      {showTemplates && <TemplateGallery onClose={() => setShowTemplates(false)} />}
    </div>
  );
};

export default App;
